import { Component, EventEmitter, h, Prop, Event, Host } from '@stencil/core';

@Component({
  tag: 'mx-file-upload-dropzone'
})
export class MxFileUploadDropzone {

  /** determine if dropzone is compact **/
  @Prop() readonly isCompact: boolean = false;
  /** height of the dropzone **/
  @Prop() readonly height: number = this.isCompact?13.5:17;
  /** width of the dropzone **/
  @Prop() readonly width: number = this.isCompact?18.625:33.438;

  /** event when file drop on the dropzone **/
  @Event() handleFiles: EventEmitter<FileList>;

  private dropzone!: HTMLInputElement;

  private readonly handleDrop = (event) => {
    this.preventDefaultsEvent(event);
    this.unHighlightDropArea(event);
    this.handleFiles.emit(event.dataTransfer.files);
  };

  private readonly highlightDropArea = (event) => {
    this.preventDefaultsEvent(event);
    this.dropzone.classList.add('bg-brand-most-subtle', 'border-brand-less-prominent', 'mx-file-upload__highlighted');
  };

  private readonly unHighlightDropArea = (event) => {
    this.preventDefaultsEvent(event);
    this.dropzone.classList.remove(
      'bg-brand-most-subtle',
      'border-brand-less-prominent', 
      'mx-file-upload__highlighted'
    );
  };

  private preventDefaultsEvent = (e) => {
    e.preventDefault();
    e.stopPropagation();
  };

  render() {
    return (
      <Host ref={(el) => this.dropzone = el as HTMLInputElement}
        onDrop={this.handleDrop}
        onDragEnter={this.highlightDropArea}
        onDragOver={this.highlightDropArea}
        onDragLeave={this.unHighlightDropArea}
        class={{
          'mx-file-upload__dropzone': true,
          'flex items-center justify-center flex-col gap-2': true,
          'rounded-8 border-thick border-dashed': true,
          'p-24 compact': this.isCompact,
          'p-32': !this.isCompact
        }}
        style={{
          height: `${this.height}rem`,
          width: `${this.width}rem`,
          display: 'block'
        }}>
        <slot />
      </Host>
    );
  }
}
